async (params, browser) => {
  // Open deals page
  await browser.open('https://www.aliexpress.com/campaign/wow/gcp/superdeal-g/index')

  // Wait for deals
  await browser.waitForSelector('[class*=\'product\'], [class*=\'item\'], [class*=\'card\']', 15000)

  await browser.wait(2000)

  // Scroll for more deals
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract deals
  const deals_data = await browser.evaluate(`const deals = []; const items = document.querySelectorAll('[class*="product-card"], [class*="item-card"], [class*="deal-card"]'); for (let i = 0; i < Math.min(items.length, 20); i++) { const el = items[i]; const titleEl = el.querySelector('[class*="title"], h3, [class*="name"]'); const dealPriceEl = el.querySelector('[class*="price"][class*="sale"], [class*="price"][class*="current"], [class*="Price"]'); const originalPriceEl = el.querySelector('[class*="price"][class*="original"], del, s, [class*="del"]'); const discountEl = el.querySelector('[class*="discount"], [class*="off"]'); const imgEl = el.querySelector('img'); const linkEl = el.querySelector('a[href*="/item/"], a'); deals.push({ title: titleEl ? titleEl.textContent.trim().substring(0, 200) : '', deal_price: dealPriceEl ? dealPriceEl.textContent.trim() : '', original_price: originalPriceEl ? originalPriceEl.textContent.trim() : '', discount: discountEl ? discountEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { deal_count: deals.length, deals: deals, url: window.location.href }`)

  return deals_data
}
